/**
 * Analytics models for dashboard reporting.
 */

/**
 * Aggregate summary across all users and orders.
 */
export interface AnalyticsSummary {
  totalUsers: number;
  totalOrders: number;
  revenue: number;
  activeUsers: number;
}

/**
 * Per-user analytics breakdown.
 */
export interface UserAnalytics {
  userId: string;
  orderCount: number;
  totalSpent: number;
  lastActive: Date;
}

/**
 * A single data point in a time-series trend.
 */
export interface TrendPoint {
  timestamp: Date;
  metric: string;
  value: number;
}

/**
 * Analytics service — aggregates data for dashboard reporting.
 *
 * Depends on:
 * - UserRepository (data layer) for user statistics
 * - OrderRepository (data layer) for order and revenue statistics
 */

import type { AnalyticsSummary, UserAnalytics, TrendPoint } from '../models/analytics.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private userRepository: UserRepository,
    private orderRepository: OrderRepository,
  ) {}

  /**
   * Get aggregate summary statistics.
   */
  getSummary(): AnalyticsSummary {
    this.logger.info('Generating analytics summary');

    const users = this.userRepository.findAll();
    const orders = this.orderRepository.findAll();

    const revenue = orders.reduce((sum, order) => sum + order.total, 0);

    const userIdsWithOrders = new Set(orders.map((order) => order.userId));
    const activeUsers = userIdsWithOrders.size;

    return {
      totalUsers: users.length,
      totalOrders: orders.length,
      revenue,
      activeUsers,
    };
  }

  /**
   * Get analytics for a specific user.
   */
  getUserAnalytics(userId: string): UserAnalytics {
    this.logger.info(`Generating analytics for user: ${userId}`);

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const orders = this.orderRepository.findByUserId(userId);
    const totalSpent = orders.reduce((sum, order) => sum + order.total, 0);

    const lastActive = orders.length > 0
      ? orders.reduce((latest, order) =>
          order.createdAt > latest ? order.createdAt : latest, orders[0]!.createdAt)
      : user.createdAt;

    return {
      userId,
      orderCount: orders.length,
      totalSpent,
      lastActive,
    };
  }

  /**
   * Get time-series trend data for a given metric within a date range.
   */
  getTrends(metric: string, startDate: Date, endDate: Date): TrendPoint[] {
    this.logger.info(`Generating trends for metric: ${metric}`);

    if (startDate > endDate) {
      throw new Error('startDate must be before endDate');
    }

    const orders = this.orderRepository.findAll();
    const filteredOrders = orders.filter(
      (order) => order.createdAt >= startDate && order.createdAt <= endDate,
    );

    if (metric === 'revenue') {
      return filteredOrders.map((order) => ({
        timestamp: order.createdAt,
        metric,
        value: order.total,
      }));
    }

    if (metric === 'orders') {
      return filteredOrders.map((order) => ({
        timestamp: order.createdAt,
        metric,
        value: 1,
      }));
    }

    if (metric === 'users') {
      const users = this.userRepository.findAll();
      const filteredUsers = users.filter(
        (user) => user.createdAt >= startDate && user.createdAt <= endDate,
      );
      return filteredUsers.map((user) => ({
        timestamp: user.createdAt,
        metric,
        value: 1,
      }));
    }

    throw new Error(`Unknown metric: ${metric}`);
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  const now = new Date('2025-06-15T12:00:00Z');

  function createUser(overrides: Partial<User> = {}): User {
    return {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: now,
      updatedAt: now,
      ...overrides,
    };
  }

  function createOrder(overrides: Partial<Order> = {}): Order {
    return {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: now,
      updatedAt: now,
      ...overrides,
    };
  }

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(userRepo, orderRepo);
  });

  describe('getSummary', () => {
    it('should return zeros when no data exists', () => {
      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(0);
      expect(summary.totalOrders).toBe(0);
      expect(summary.revenue).toBe(0);
      expect(summary.activeUsers).toBe(0);
    });

    it('should aggregate stats across users and orders', () => {
      userRepo.save(createUser({ id: 'user-1' }));
      userRepo.save(createUser({ id: 'user-2', email: 'bob@example.com' }));
      userRepo.save(createUser({ id: 'user-3', email: 'carol@example.com' }));

      orderRepo.save(createOrder({ id: 'order-1', userId: 'user-1', total: 50 }));
      orderRepo.save(createOrder({ id: 'order-2', userId: 'user-1', total: 30 }));
      orderRepo.save(createOrder({ id: 'order-3', userId: 'user-2', total: 20 }));

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(3);
      expect(summary.totalOrders).toBe(3);
      expect(summary.revenue).toBe(100);
      expect(summary.activeUsers).toBe(2);
    });

    it('should count active users as those with orders', () => {
      userRepo.save(createUser({ id: 'user-1' }));
      userRepo.save(createUser({ id: 'user-2', email: 'bob@example.com' }));

      orderRepo.save(createOrder({ id: 'order-1', userId: 'user-1', total: 10 }));

      const summary = service.getSummary();
      expect(summary.activeUsers).toBe(1);
    });
  });

  describe('getUserAnalytics', () => {
    it('should throw for non-existent user', () => {
      expect(() => service.getUserAnalytics('nonexistent')).toThrow('User not found');
    });

    it('should return analytics for user with no orders', () => {
      const user = createUser({ id: 'user-1' });
      userRepo.save(user);

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.orderCount).toBe(0);
      expect(analytics.totalSpent).toBe(0);
      expect(analytics.lastActive).toEqual(user.createdAt);
    });

    it('should calculate order count and total spent', () => {
      userRepo.save(createUser({ id: 'user-1' }));
      orderRepo.save(createOrder({ id: 'order-1', userId: 'user-1', total: 50 }));
      orderRepo.save(createOrder({ id: 'order-2', userId: 'user-1', total: 30 }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(80);
    });

    it('should use most recent order date as lastActive', () => {
      const earlier = new Date('2025-01-01T00:00:00Z');
      const later = new Date('2025-06-01T00:00:00Z');

      userRepo.save(createUser({ id: 'user-1' }));
      orderRepo.save(createOrder({ id: 'order-1', userId: 'user-1', createdAt: earlier }));
      orderRepo.save(createOrder({ id: 'order-2', userId: 'user-1', createdAt: later }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.lastActive).toEqual(later);
    });
  });

  describe('getTrends', () => {
    it('should throw if startDate is after endDate', () => {
      const start = new Date('2025-06-15');
      const end = new Date('2025-06-01');

      expect(() => service.getTrends('revenue', start, end)).toThrow(
        'startDate must be before endDate',
      );
    });

    it('should throw for unknown metric', () => {
      const start = new Date('2025-01-01');
      const end = new Date('2025-12-31');

      expect(() => service.getTrends('unknown', start, end)).toThrow('Unknown metric');
    });

    it('should return revenue trend points', () => {
      userRepo.save(createUser({ id: 'user-1' }));
      orderRepo.save(createOrder({
        id: 'order-1',
        total: 50,
        createdAt: new Date('2025-03-01T00:00:00Z'),
      }));
      orderRepo.save(createOrder({
        id: 'order-2',
        total: 30,
        createdAt: new Date('2025-06-01T00:00:00Z'),
      }));

      const trends = service.getTrends(
        'revenue',
        new Date('2025-01-01'),
        new Date('2025-12-31'),
      );

      expect(trends).toHaveLength(2);
      expect(trends[0]?.metric).toBe('revenue');
      expect(trends[0]?.value).toBe(50);
      expect(trends[1]?.value).toBe(30);
    });

    it('should filter trend data by date range', () => {
      userRepo.save(createUser({ id: 'user-1' }));
      orderRepo.save(createOrder({
        id: 'order-1',
        total: 50,
        createdAt: new Date('2025-03-01T00:00:00Z'),
      }));
      orderRepo.save(createOrder({
        id: 'order-2',
        total: 30,
        createdAt: new Date('2025-09-01T00:00:00Z'),
      }));

      const trends = service.getTrends(
        'revenue',
        new Date('2025-01-01'),
        new Date('2025-06-30'),
      );

      expect(trends).toHaveLength(1);
      expect(trends[0]?.value).toBe(50);
    });

    it('should return order count trend points', () => {
      userRepo.save(createUser({ id: 'user-1' }));
      orderRepo.save(createOrder({
        id: 'order-1',
        createdAt: new Date('2025-03-01T00:00:00Z'),
      }));

      const trends = service.getTrends(
        'orders',
        new Date('2025-01-01'),
        new Date('2025-12-31'),
      );

      expect(trends).toHaveLength(1);
      expect(trends[0]?.metric).toBe('orders');
      expect(trends[0]?.value).toBe(1);
    });

    it('should return user registration trend points', () => {
      userRepo.save(createUser({
        id: 'user-1',
        createdAt: new Date('2025-03-01T00:00:00Z'),
      }));
      userRepo.save(createUser({
        id: 'user-2',
        email: 'bob@example.com',
        createdAt: new Date('2025-06-01T00:00:00Z'),
      }));

      const trends = service.getTrends(
        'users',
        new Date('2025-01-01'),
        new Date('2025-12-31'),
      );

      expect(trends).toHaveLength(2);
      expect(trends[0]?.metric).toBe('users');
    });

    it('should return empty array when no data in range', () => {
      const trends = service.getTrends(
        'revenue',
        new Date('2025-01-01'),
        new Date('2025-12-31'),
      );

      expect(trends).toHaveLength(0);
    });
  });
});

